const items = [];

for (const item of $input.all()) {
  const json = item.json;

  const recipientsMap = new Map();

  const observersRaw = json.observers;

  if (!observersRaw) continue;

  const observers = observersRaw.split(',');

  for (const user of observers) {
    if (!user || !user.includes('||')) continue;

    const [email, firstname, lastname] = user.split('||');

    if (!email) continue;

    recipientsMap.set(email.trim(), {
      email: email.trim(),
      firstname: firstname?.trim() || '',
      lastname: lastname?.trim() || ''
    });
  }

  recipientsMap.forEach(recipient => {
    items.push({
      json: {
        ...json,
        recipient_email: recipient.email,
        recipient_firstname: recipient.firstname,
        recipient_lastname: recipient.lastname
      }
    });
  });
}

return items;
